%% baseline_sweep.m
clear; clc;

L_values_um = 40:5:160;
nL = length(L_values_um);
CV = zeros(1, nL);

for k = 1:nL %[output:group:19da572a]

    load('Carcamo2017CortexAxon.mat');
    par = axon;

    % Keep nintseg at 86 - reducing it changes the biology
    % Only increase tmax slightly for longer internodes
    par.sim.tmax.value = 3;

    % Only biological parameter we vary - strict isolation
    par = UpdateInternodeLength(par, L_values_um(k));

    [MEMBRANE_POTENTIAL, INTERNODE_LENGTH, TIME_VECTOR] = Model(par, [], false);

    dt = TIME_VECTOR(2) - TIME_VECTOR(1);
    CV(k) = velocities(MEMBRANE_POTENTIAL, INTERNODE_LENGTH, dt, [20, 30]);

    fprintf('L = %3d um -> CV = %.3f m/s\n', L_values_um(k), CV(k)); %[output:3e4a7f3f]
end %[output:group:19da572a]

save('results_CV.mat', 'L_values_um', 'CV');

figure; %[output:46a87a7a]
plot(L_values_um, CV, 'o-', 'LineWidth', 2, 'Color', [0.2 0.4 0.8], ... %[output:46a87a7a]
     'MarkerFaceColor', [0.2 0.4 0.8]); %[output:46a87a7a]
xlabel('Internode length (µm)'); %[output:46a87a7a]
ylabel('Conduction velocity (m/s)'); %[output:46a87a7a]
title('CV vs homogeneous internode length'); %[output:46a87a7a]
xline(81.7, '--k', 'Default 81.7 µm'); %[output:46a87a7a]
grid on; %[output:46a87a7a]

